import polars as pl

df = pl.DataFrame({
    "name": ["Alice", "Bob", "Charlie"],
    "dept": ["Eng", "Mkt", "Eng"],
    "salary": [95000, 78000, 120000],
})

result = df.filter(
    pl.col("dept") == "Eng"
).select(
    pl.col("name"),
    (pl.col("salary") / 12).round(0).alias("monthly"),
)

print(result)
